CREATE TYPE "IntegrationAutomationStatus" AS ENUM ('DRAFT','PUBLISHED','ARCHIVED');
CREATE TYPE "IntegrationAutomationTrigger" AS ENUM ('MANUAL','SCHEDULED','EVENT','WEBHOOK','DATA_SYNC');
CREATE TYPE "IntegrationAutomationNodeType" AS ENUM ('TRIGGER','CONDITION','ACTION','DELAY','APPROVAL','CONNECTOR','WEBHOOK');
CREATE TYPE "IntegrationAutomationRunStatus" AS ENUM ('PENDING','RUNNING','WAITING_APPROVAL','SUCCEEDED','FAILED','CANCELLED');
CREATE TYPE "IntegrationAutomationStepStatus" AS ENUM ('PENDING','RUNNING','WAITING_APPROVAL','SUCCEEDED','FAILED','RETRY_SCHEDULED','SKIPPED','CANCELLED');
CREATE TYPE "IntegrationAutomationApprovalStatus" AS ENUM ('PENDING','APPROVED','REJECTED','CANCELLED');
CREATE TABLE "IntegrationAutomation" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"status" "IntegrationAutomationStatus" NOT NULL DEFAULT 'DRAFT',"triggerType" "IntegrationAutomationTrigger" NOT NULL,"triggerConfig" JSONB,"enabled" BOOLEAN NOT NULL DEFAULT true,"version" INTEGER NOT NULL DEFAULT 0,"tags" TEXT[] DEFAULT ARRAY[]::TEXT[],"createdByUserId" TEXT NOT NULL,"publishedByUserId" TEXT,"publishedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "IntegrationAutomationNode" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"automationId" TEXT NOT NULL,"key" TEXT NOT NULL,"name" TEXT NOT NULL,"type" "IntegrationAutomationNodeType" NOT NULL,"config" JSONB,"maxAttempts" INTEGER NOT NULL DEFAULT 3,"timeoutSeconds" INTEGER NOT NULL DEFAULT 300,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "IntegrationAutomationEdge" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"automationId" TEXT NOT NULL,"fromNodeKey" TEXT NOT NULL,"toNodeKey" TEXT NOT NULL,"outcome" TEXT NOT NULL DEFAULT 'SUCCESS',"condition" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "IntegrationAutomationRun" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"automationId" TEXT NOT NULL,"status" "IntegrationAutomationRunStatus" NOT NULL DEFAULT 'PENDING',"triggerType" "IntegrationAutomationTrigger" NOT NULL,"correlationId" TEXT NOT NULL,"idempotencyKey" TEXT,"input" JSONB,"output" JSONB,"errorMessage" TEXT,"triggeredByUserId" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "IntegrationAutomationStepRun" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"runId" TEXT NOT NULL,"nodeId" TEXT NOT NULL,"status" "IntegrationAutomationStepStatus" NOT NULL DEFAULT 'PENDING',"attempt" INTEGER NOT NULL DEFAULT 1,"input" JSONB,"output" JSONB,"errorMessage" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"nextAttemptAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "IntegrationAutomationApproval" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"runId" TEXT NOT NULL,"stepId" TEXT NOT NULL,"status" "IntegrationAutomationApprovalStatus" NOT NULL DEFAULT 'PENDING',"requestedByUserId" TEXT,"approverUserId" TEXT,"decidedByUserId" TEXT,"decisionNotes" TEXT,"decidedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
ALTER TABLE "IntegrationAutomationNode" ADD CONSTRAINT "IntegrationAutomationNode_automationId_fkey" FOREIGN KEY ("automationId") REFERENCES "IntegrationAutomation"("id") ON DELETE CASCADE;
ALTER TABLE "IntegrationAutomationEdge" ADD CONSTRAINT "IntegrationAutomationEdge_automationId_fkey" FOREIGN KEY ("automationId") REFERENCES "IntegrationAutomation"("id") ON DELETE CASCADE;
ALTER TABLE "IntegrationAutomationRun" ADD CONSTRAINT "IntegrationAutomationRun_automationId_fkey" FOREIGN KEY ("automationId") REFERENCES "IntegrationAutomation"("id") ON DELETE CASCADE;
ALTER TABLE "IntegrationAutomationStepRun" ADD CONSTRAINT "IntegrationAutomationStepRun_runId_fkey" FOREIGN KEY ("runId") REFERENCES "IntegrationAutomationRun"("id") ON DELETE CASCADE;
ALTER TABLE "IntegrationAutomationStepRun" ADD CONSTRAINT "IntegrationAutomationStepRun_nodeId_fkey" FOREIGN KEY ("nodeId") REFERENCES "IntegrationAutomationNode"("id") ON DELETE RESTRICT;
ALTER TABLE "IntegrationAutomationApproval" ADD CONSTRAINT "IntegrationAutomationApproval_runId_fkey" FOREIGN KEY ("runId") REFERENCES "IntegrationAutomationRun"("id") ON DELETE CASCADE;
ALTER TABLE "IntegrationAutomationApproval" ADD CONSTRAINT "IntegrationAutomationApproval_stepId_fkey" FOREIGN KEY ("stepId") REFERENCES "IntegrationAutomationStepRun"("id") ON DELETE CASCADE;
CREATE UNIQUE INDEX "IntegrationAutomation_org_name_version_key" ON "IntegrationAutomation"("organizationId","name","version");
CREATE UNIQUE INDEX "IntegrationAutomationNode_automation_key_key" ON "IntegrationAutomationNode"("automationId","key");
CREATE UNIQUE INDEX "IntegrationAutomationEdge_path_key" ON "IntegrationAutomationEdge"("automationId","fromNodeKey","toNodeKey","outcome");
CREATE UNIQUE INDEX "IntegrationAutomationRun_idempotency_key" ON "IntegrationAutomationRun"("organizationId","automationId","idempotencyKey");
CREATE INDEX "IntegrationAutomation_org_status_idx" ON "IntegrationAutomation"("organizationId","status","enabled");
CREATE INDEX "IntegrationAutomationRun_org_status_created_idx" ON "IntegrationAutomationRun"("organizationId","status","createdAt");
CREATE INDEX "IntegrationAutomationStepRun_org_status_next_idx" ON "IntegrationAutomationStepRun"("organizationId","status","nextAttemptAt");
CREATE INDEX "IntegrationAutomationApproval_org_status_idx" ON "IntegrationAutomationApproval"("organizationId","status","createdAt");
